func TestBuildPromptFull(t *testing.T) {
	got := BuildPrompt(
		[]types.TopicRef{
			{Slug: "go-migration", Name: "Go Migration"},
			{Slug: "obs-setup", Name: "OBS Setup"},
		},
		"en",
		"/tmp/proj/.state/tmp/transcript-abc123.txt",
	)
	if got != expectedPromptFull {
		t.Errorf("BuildPrompt mismatch:\n--- got ---\n%q\n--- want ---\n%q", got, expectedPromptFull)
	}
}

func TestBuildPromptEmptyLibraryUnknownLanguage(t *testing.T) {
	got := BuildPrompt(nil, "unknown", "")
	if got != expectedPromptEmptyUnknown {
		t.Errorf("BuildPrompt mismatch:\n--- got ---\n%q\n--- want ---\n%q", got, expectedPromptEmptyUnknown)
	}
}

func TestBuildPromptExistingTopicsNoPath(t *testing.T) {
	got := BuildPrompt([]types.TopicRef{{Slug: "produto", Name: "Produto"}}, "pt", "")
	if got != expectedPromptTopicsNoPathPt {
		t.Errorf("BuildPrompt mismatch:\n--- got ---\n%q\n--- want ---\n%q", got, expectedPromptTopicsNoPathPt)
	}
}

func TestBuildPromptKeyBlocks(t *testing.T) {
	withTopics := BuildPrompt([]types.TopicRef{{Slug: "a", Name: "A"}}, "en", "/tmp/t.txt")
	for _, block := range []string{
		"First, read the meeting transcript from this file using your file reading tool: /tmp/t.txt\n" +
			"Base your entire analysis on its contents.",
		"The knowledge library already contains these topics (slug: name):\n- a: A\n",
		"REUSE an existing slug whenever the subject of a topic matches.",
		`in the same language as the transcript ("en").`,
	} {
		if !strings.Contains(withTopics, block) {
			t.Errorf("prompt with topics missing block %q", block)
		}
	}
	if strings.Contains(withTopics, "The knowledge library is empty yet.") {
		t.Error("prompt with topics must not contain the empty-library block")
	}

	empty := BuildPrompt(nil, "", "")
	for _, block := range []string{
		"Analyze the meeting transcript provided with this request.",
		"The knowledge library is empty yet. Create slugs for every subject discussed.",
		"in the same language the transcript is written in.",
	} {
		if !strings.Contains(empty, block) {
			t.Errorf("empty-library prompt missing block %q", block)
		}
	}
	if strings.Contains(empty, "REUSE an existing slug") {
		t.Error("empty-library prompt must not contain the reuse block")
	}

	// "" and "unknown" languages produce the same rule.
	if BuildPrompt(nil, "", "") != BuildPrompt(nil, "unknown", "") {
		t.Error(`language "" and "unknown" should produce identical prompts`)
	}
}

func TestParseAnalysisCleanJSON(t *testing.T) {
	raw := `{
	  "meeting": {
	    "title": "Go migration kickoff",
	    "summary": "The team planned the Go port.",
	    "key_points": ["port analyzer first", "keep JSON contract"],
	    "decisions": ["use AssemblyAI SDK"],
	    "action_items": [{"owner": "Ana", "task": "write tests"}]
	  },
	  "topics": [
	    {"slug": "go-migration", "name": "Go Migration", "content": "Port started."}
	  ]
	}`
	got := ParseAnalysis(raw, "Test")
	if got.Title != "Go migration kickoff" {
		t.Errorf("Title = %q", got.Title)
	}
	if got.Summary != "The team planned the Go port." {
		t.Errorf("Summary = %q", got.Summary)
	}
	if len(got.KeyPoints) != 2 || got.KeyPoints[0] != "port analyzer first" || got.KeyPoints[1] != "keep JSON contract" {
		t.Errorf("KeyPoints = %v", got.KeyPoints)
	}
	if len(got.Decisions) != 1 || got.Decisions[0] != "use AssemblyAI SDK" {
		t.Errorf("Decisions = %v", got.Decisions)
	}
	if len(got.ActionItems) != 1 || got.ActionItems[0] != (types.ActionItem{Owner: "Ana", Task: "write tests"}) {
		t.Errorf("ActionItems = %v", got.ActionItems)
	}
	if len(got.Topics) != 1 || got.Topics[0] != (types.Topic{Slug: "go-migration", Name: "Go Migration", Content: "Port started."}) {
		t.Errorf("Topics = %v", got.Topics)
	}
}

func TestParseAnalysisFencedJSON(t *testing.T) {
	body := `{"meeting": {"title": "Fenced", "summary": "s"}, "topics": []}`
	for _, raw := range []string{
		"```json\n" + body + "\n```",
		"```\n" + body + "\n```",
		"  ```json  " + body + " ```  ",
	} {
		got := ParseAnalysis(raw, "Test")
		if got.Title != "Fenced" {
			t.Errorf("ParseAnalysis(%q).Title = %q, want %q", raw, got.Title, "Fenced")
		}
	}
}

func TestParseAnalysisProseWrappedJSON(t *testing.T) {
	raw := `Here is the analysis you asked for:

{"meeting": {"title": "Prose", "summary": "wrapped"}, "topics": [{"slug": "x"}]}

Hope this helps!`
	got := ParseAnalysis(raw, "Test")
	if got.Title != "Prose" {
		t.Errorf("Title = %q, want %q", got.Title, "Prose")
	}
	if got.Summary != "wrapped" {
		t.Errorf("Summary = %q, want %q", got.Summary, "wrapped")
	}
	if len(got.Topics) != 1 || got.Topics[0].Slug != "x" {
		t.Errorf("Topics = %v", got.Topics)
	}
}

func TestParseAnalysisMissingMeetingFallback(t *testing.T) {
	raw := `{"topics": [{"slug": "x", "content": "y"}]}`
	got := ParseAnalysis(raw, "Test")
	wantSummary := strings.TrimSpace(raw)
	if got.Title != "Untitled meeting" {
		t.Errorf("Title = %q, want %q", got.Title, "Untitled meeting")
	}
	if got.Summary != wantSummary {
		t.Errorf("Summary = %q, want %q", got.Summary, wantSummary)
	}
	if len(got.Topics) != 1 ||
		got.Topics[0] != (types.Topic{Slug: "general", Name: "General", Content: wantSummary}) {
		t.Errorf("Topics = %v", got.Topics)
	}
}

func TestParseAnalysisGarbageFallback(t *testing.T) {
	got := ParseAnalysis("this is not JSON at all", "Test")
	if got.Title != "Untitled meeting" {
		t.Errorf("Title = %q", got.Title)
	}
	if got.Summary != "this is not JSON at all" {
		t.Errorf("Summary = %q", got.Summary)
	}
	if len(got.Topics) != 1 || got.Topics[0].Slug != "general" || got.Topics[0].Name != "General" ||
		got.Topics[0].Content != got.Summary {
		t.Errorf("Topics = %v", got.Topics)
	}
}

func TestParseAnalysisEmptyFallback(t *testing.T) {
	got := ParseAnalysis("   \n  ", "Test")
	want := "Analysis failed to produce a parseable result."
	if got.Summary != want {
		t.Errorf("Summary = %q, want %q", got.Summary, want)
	}
	if len(got.Topics) != 1 || got.Topics[0].Content != want {
		t.Errorf("Topics = %v", got.Topics)
	}
}

func TestParseAnalysisFallbackTruncatesTo2000Runes(t *testing.T) {
	raw := strings.Repeat("é", 2500) // multi-byte: rune count is what matters
	got := ParseAnalysis(raw, "Test")
	if n := len([]rune(got.Summary)); n != 2000 {
		t.Errorf("len(Summary) = %d runes, want 2000", n)
	}
}

func TestParseAnalysisStringActionItems(t *testing.T) {
	raw := `{"meeting": {
	  "title": "t",
	  "summary": "s",
	  "action_items": [
	    "review the PR",
	    {"owner": "Bob", "task": "deploy"},
	    {"task": "no owner given"},
	    {"owner": null, "task": "null owner"},
	    "",
	    0
	  ]
	}}`
	got := ParseAnalysis(raw, "Test")
	want := []types.ActionItem{
		{Owner: "unassigned", Task: "review the PR"},
		{Owner: "Bob", Task: "deploy"},
		{Owner: "unassigned", Task: "no owner given"},
		{Owner: "None", Task: "null owner"}, // Python str(None)
	}
	if len(got.ActionItems) != len(want) {
		t.Fatalf("ActionItems = %v, want %v", got.ActionItems, want)
	}
	for i, item := range want {
		if got.ActionItems[i] != item {
			t.Errorf("ActionItems[%d] = %v, want %v", i, got.ActionItems[i], item)
		}
	}
}

func TestParseAnalysisTopicDefaults(t *testing.T) {
	raw := `{"meeting": {"title": "t", "summary": "s"}, "topics": [
	  {"slug": "only-slug"},
	  {"slug": "full", "name": "Full Name", "content": "content here"},
	  {"name": "no slug", "content": "skipped"},
	  {"slug": ""},
	  "not an object",
	  {"slug": "null-name", "name": null, "content": null}
	]}`
	got := ParseAnalysis(raw, "Test")
	want := []types.Topic{
		{Slug: "only-slug", Name: "only-slug", Content: ""},
		{Slug: "full", Name: "Full Name", Content: "content here"},
		{Slug: "null-name", Name: "null-name", Content: ""},
	}
	if len(got.Topics) != len(want) {
		t.Fatalf("Topics = %v, want %v", got.Topics, want)
	}
	for i, topic := range want {
		if got.Topics[i] != topic {
			t.Errorf("Topics[%d] = %v, want %v", i, got.Topics[i], topic)
		}
	}
}

func TestParseAnalysisTitleAndListDefaults(t *testing.T) {
	// Missing title defaults; non-list key_points/decisions are ignored.
	raw := `{"meeting": {"summary": "s", "key_points": "not a list", "decisions": 42}}`
	got := ParseAnalysis(raw, "Test")
	if got.Title != "Untitled meeting" {
		t.Errorf("Title = %q, want %q", got.Title, "Untitled meeting")
	}
	if len(got.KeyPoints) != 0 {
		t.Errorf("KeyPoints = %v, want empty", got.KeyPoints)
	}
	if len(got.Decisions) != 0 {
		t.Errorf("Decisions = %v, want empty", got.Decisions)
	}

	// Empty title also falls back to the default.
	raw = `{"meeting": {"title": "", "summary": "s"}, "topics": []}`
	if got := ParseAnalysis(raw, "Test"); got.Title != "Untitled meeting" {
		t.Errorf("Title = %q, want %q", got.Title, "Untitled meeting")
	}
}
